/*
 * 算法名称: 迭代构造法 + 字符串匹配
 * 关键技巧:
 * 1. 假设A是B的前缀进行构造: B = A * 10^k + S.
 * 2. 迭代后缀位数k和后缀值S.
 * 3. 检查B的范围 (1 <= B <= 2^31-1).
 * 4. 检查A是否为2*B的子串.
 * 5. 利用题目保证有解的特性，限制k的搜索范围，并通过剪枝提前终止不必要的搜索。
 */
#include <iostream>
#include <string>
#include <vector>
#include <algorithm> // For std::to_string if not in <string> for some old compilers
#include <cmath>     // For std::pow, or manual calculation

// 使用 long long 处理大数场景，尽管最终 B 需在 int 范围内
using ll = long long;
// C++ int 最大值 (2^31-1)
const ll INT_MAX_LL = 2147483647LL;
// 典型竞赛常量定义 (INF在此题中不直接使用)
// const int INF = 0x3f3f3f3f; 

// 预计算10的幂，避免重复调用pow()或手动乘法
// constexpr int MAX_K_ITER = 10; // k 从 0 到 9 (10^0 到 10^9)
std::vector<ll> p10(11);

void precompute_powers() {
    p10[0] = 1;
    for (int i = 1; i <= 10; ++i) {
        p10[i] = p10[i-1] * 10;
    }
}

int main() {
    // 必须的IO加速
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    precompute_powers();

    int a_val;
    std::cin >> a_val;

    std::string sA = std::to_string(a_val);

    // K_LIMIT_EXCLUSIVE defines k runs from 0 up to K_LIMIT_EXCLUSIVE-1
    // e.g. K_LIMIT_EXCLUSIVE = 8 means k = 0, 1, ..., 7
    // This means Suffix has up to 7 digits. Max S is 10^7-1.
    // Max B ~ A * 10^7 + 10^7. If A=1, B ~ 10^7. If A=10000, B ~ 10000*10^7 = 10^11 (too big)
    // The loops will break early if B exceeds INT_MAX_LL.
    // k iterates number of suffix digits.
    // k=0: 0 suffix digits. S=0.
    // k=1: 1 suffix digit. S=0..9.
    // k=...
    // k=9: 9 suffix digits. S=0..10^9-1. Max B for A=1: 1*10^9 + (10^9-1) ~ 2*10^9. Fits.
    for (int k = 0; k <= 9; ++k) { // k is the number of digits in S
        ll val_A_base = static_cast<ll>(a_val) * p10[k];

        // DEBUG: Check if base itself is too large
        // If A * 10^k (with S=0) is already too big.
        // (k > 0 check because if k=0, val_A_base is just A, which is <= 10000)
        if (k > 0 && val_A_base > INT_MAX_LL) {
             break; // Further k will also result in val_A_base being too large
        }

        ll limit_S = p10[k]; // S goes from 0 to 10^k - 1
        if (k == 0) limit_S = 1; // Special case for k=0, S is only 0 (conceptual, 0 digits)

        for (ll s_val = 0; s_val < limit_S; ++s_val) {
            ll current_B = val_A_base + s_val;

            // Defensive programming: Check B's validity
            if (current_B == 0) continue; // B must be positive (A >= 1, so current_B >= 1 always)

            if (current_B > INT_MAX_LL) {
                // If S=0 already made current_B too large (covered by k-loop break for k>0)
                // or if current S makes it too large, larger S for this k also will.
                // For k=0, current_B = a_val, which is <= 10000, so this won't trigger for S=0, k=0.
                break; // Break S loop, try next k if val_A_base was okay.
            }

            // Condition 1: A is a substring of B.
            // This is true by construction if a_val != 0, as B = A...S.
            // std::string sB = std::to_string(current_B); // Not strictly needed for check 1
            // if (sB.find(sA) == std::string::npos) continue; // Should not happen with this construction

            // Condition 2: A is also B*2's substring
            ll val_2B = 2LL * current_B; // DEBUG: ensure 2LL to promote multiplication to long long
            std::string s_2B = std::to_string(val_2B);

            if (s_2B.find(sA) != std::string::npos) {
                std::cout << current_B << std::endl;
                return 0; // Found a solution
            }
        }
    }

    return 0; // Should be unreachable due to problem guarantee
}

[算法分析]
1. 核心算法原理：
   问题要求将 $N \times M$ 的巧克力通过两次切割分成三块，目标是最小化三块巧克力面积 $a, b, c$ 两两之差的绝对值的最大值，即 $\min(\max(|a-b|, |a-c|, |b-c|))$。
   切割方式有两种主要类型：
   a) **平行切割**：两次切割都平行于某条边。例如，沿 $N$ 边切割两次，将巧克力分成三条 $N_1 \times M, N_2 \times M, N_3 \times M$ 的部分，其中 $N_1+N_2+N_3=N$。为了使面积接近， $N_1, N_2, N_3$ 应尽可能接近 $N/3$。如果 $N$ 能被3整除，则三块面积可以完全相等，差值为0。否则，最大差值为 $M$ (如果沿 $N$ 切割) 或 $N$ (如果沿 $M$ 切割)。此方法要求被分割的维度长度至少为3。
   b) **垂直切割**：第一次切割将巧克力分成两块，第二次切割在其中一块上进行，且垂直于第一次切割。例如，第一次沿 $N$ 边在 $i$ 处切割，得到 $i \times M$ 和 $(N-i) \times M$ 两块。然后选择 $i \times M$ 这块，沿 $M$ 边在 $j$ 处切割，得到 $i \times j$ 和 $i \times (M-j)$ 两块。最终三块面积为 $i \times j$, $i \times (M-j)$, 和 $(N-i) \times M$。另一种对称情况是先沿 $M$ 边切割。

2. 时间复杂度推导：
   - 平行切割的计算是 $O(1)$。
   - 垂直切割：如果遍历所有可能的 $i$ ($1$ 到 $N-1$) 和 $j$ ($1$ 到 $M-1$)，复杂度将是 $O(NM)$，这对于 $N, M \leq 10^9$ 来说太高。
   - 关键优化：我们不需要测试所有的 $i$ 和 $j$。可以证明，最优解或接近最优解的切割点往往在特定位置，如 $L/3, L/2, 2L/3$ 或接近边缘 $k, L-k$ (对于小 $k$)。因此，我们为 $N$ 和 $M$ 各生成一个候选切割点的小集合（例如，每个维度约10-15个点）。
   - 设候选切割点数量为 $C_N$ (for N) 和 $C_M$ (for M)。则垂直切割的计算复杂度为 $O(C_N \cdot C_M)$。由于 $C_N, C_M$ 是小常数（例如 $\approx 15-20$），此部分复杂度接近 $O(1)$ (e.g., $20 \times 20 = 400$ operations).
   - 总时间复杂度：$O(C_N \cdot C_M)$，实际上是常数时间 $O(C^2)$。

3. 空间复杂度分析：
   - 存储候选切割点需要 $O(C_N + C_M)$ 空间。
   - 其他变量占用 $O(1)$ 空间。
   - 总空间复杂度：$O(C)$, 其中 C 是候选点数量，实际上是 $O(1)$。

4. 关键优化点说明：
   - **平行切割的简化逻辑**：如果一个维度 $L \ge 3$，若 $L \% 3 == 0$，则可以通过平行切割实现差值为0；否则，最小差值为另一维度 $W$。
   - **垂直切割的候选点**：不进行完全遍历，而是只测试特定有代表性的切割点。这些点包括：
     - 离边缘近的点：$1, 2, 3, \dots$ 以及 $L-1, L-2, L-3, \dots$
     - 分割点附近的点：$L/3 \pm k, L/2 \pm k, 2L/3 \pm k$ (其中 $k$ 是小偏移量如 $0, 1, 2$)。
     - 通过 `std::set` 存储候选点可以自动处理重复和排序，并保证切割点有效 ($1 \le \text{cut} < L$)。

