```cpp
/*
Algorithm Name: Constructive Approach with Limited Search Space
Key Techniques:
1. Analyze two main cutting strategies:
   a) Parallel cuts: Divides one dimension (e.g., N) into three parts N1, N2, N3.
      - If N % 3 == 0 and N >= 3, difference can be 0.
      - Else if N >= 3, difference is M (the other dimension). Symmetric for M.
2. Perpendicular cuts: First cut divides N x M. Second cut divides one part perpendicularly.
   - E.g., cut N at i, then cut piece (i x M) at j. Pieces: i*j, i*(M-j), (N-i)*M.
   - Symmetric case: cut M at j, then cut piece (N x j) at i. Pieces: i*j, (N-i)*j, N*(M-j).
3. Optimize perpendicular cuts by testing a small, representative set of candidate cut points for i and j,
   instead of iterating N*M possibilities. Candidates include points near ends (1, 2, L-1, L-2)
   and fractions (L/3, L/2, 2L/3) with small offsets.
*/
#include <bits/stdc++.h> // Using bits/stdc++.h for convenience in competitive programming

using namespace std;
using ll = long long;  // Must handle large numbers. N, M up to 10^9, areas up to 10^18.
const ll INFLL = 4e18; // A very large number for long long, for min_overall_diff initialization.

// Function to calculate max difference for three areas and update global minimum.
void calculate_and_update_min_diff(ll piece_a, ll piece_b, ll piece_c, ll& min_overall_diff) {
    // Areas must be positive. This is implicitly handled as cuts must be >0 and <L.
    if (piece_a <= 0 || piece_b <= 0 || piece_c <= 0) {
        return; 
    }

    ll current_max_abs_diff = 0;
    current_max_abs_diff = max(current_max_abs_diff, abs(piece_a - piece_b));
    current_max_abs_diff = max(current_max_abs_diff, abs(piece_a - piece_c));
    current_max_abs_diff = max(current_max_abs_diff, abs(piece_b - piece_c));

    min_overall_diff = min(min_overall_diff, current_max_abs_diff);
}

// Generates candidate cut positions for a dimension L.
// A cut at position `k` means one piece has length `k`. `k` must be in [1, L-1].
vector<ll> get_candidate_cut_points(ll L) {
    if (L <= 1) return {}; // Cannot make a valid cut if L is 0 or 1. Problem constraints N, M >= 2.

    set<ll> cut_points_set;

    // Cuts near the ends: 1, 2, 3 and L-1, L-2, L-3
    for (ll k = 1; k <= 3; ++k) {
        if (k >= 1 && k < L) { 
            cut_points_set.insert(k);
        }
        if (L - k >= 1 && L - k < L) { 
            cut_points_set.insert(L - k);
        }
    }

    // Cuts near L/3, L/2, 2L/3
    ll L_div_3 = L / 3;
    ll L_div_2 = L / 2;
    ll L_mul_2_div_3 = (L * 2) / 3; 

    ll base_cuts_arr[] = {L_div_3, L_div_2, L_mul_2_div_3};
    for (ll base_c : base_cuts_arr) {
        for (ll delta = -2; delta <= 2; ++delta) { // Test points around base_c
            ll potential_cut = base_c + delta;
            if (potential_cut >= 1 && potential_cut < L) { 
                cut_points_set.insert(potential_cut);
            }
        }
    }

    // Ensure basic cuts like 1 are present if L is small and L/3 type calcs might miss them.
    // E.g., for L=2, L/3=0. The loop for k=1..3 handles inserting 1.
    // If L is very small, e.g. L=2, set will contain {1}. If L=3, set will contain {1,2}.
    // This seems robust.

    return vector<ll>(cut_points_set.begin(), cut_points_set.end());
}


int main() {
    ios::sync_with_stdio(false); // Standard competitive programming IO optimization
    cin.tie(nullptr);            // Untie cin from cout

    ll n_rows, m_cols; 
    cin >> n_rows >> m_cols;

    ll min_abs_diff_found = INFLL;

    // Case 1: Parallel cuts
    // This type of cut requires the dimension being split to be at least 3.
    if (n_rows >= 3) {
        if (n_rows % 3 == 0) { 
            min_abs_diff_found = min(min_abs_diff_found, 0LL);
        } else {
            min_abs_diff_found = min(min_abs_diff_found, m_cols);
        }
    }
    if (m_cols >= 3) { 
        if (m_cols % 3 == 0) {
            min_abs_diff_found = min(min_abs_diff_found, 0LL);
        } else {
            min_abs_diff_found = min(min_abs_diff_found, n_rows);
        }
    }

    // Case 2: Perpendicular cuts
    vector<ll> n_cut_point_candidates = get_candidate_cut_points(n_rows);
    vector<ll> m_cut_point_candidates = get_candidate_cut_points(m_cols);

    // Configuration A: First cut horizontal, second vertical on one of the pieces.
    // Pieces: (n_len1 * m_len1), (n_len1 * m_len2), (n_len2 * M_total)
    for (ll n_len1 : n_cut_point_candidates) { 
        ll n_len2 = n_rows - n_len1; // Length of the second part along N-dimension

        for (ll m_len1 : m_cut_point_candidates) { 
            ll m_len2 = m_cols - m_len1; // Length of the second part along M-dimension

            ll piece1 = n_len1 * m_len1;
            ll piece2 = n_len1 * m_len2;
            ll piece3 = n_len2 * m_cols; // The undivided piece
            calculate_and_update_min_diff(piece1, piece2, piece3, min_abs_diff_found); // DEBUG: Marked for key logic
        }
    }

    // Configuration B: First cut vertical, second horizontal on one of the pieces.
    // Pieces: (n_len1 * m_len1), (n_len2 * m_len1), (N_total * m_len2)
    for (ll m_len1 : m_cut_point_candidates) {
        ll m_len2 = m_cols - m_len1;

        for (ll n_len1 : n_cut_point_candidates) {
            ll n_len2 = n_rows - n_len1;

            ll piece1 = n_len1 * m_len1;
            ll piece2 = n_len2 * m_len1;
            ll piece3 = n_rows * m_len2; // The undivided piece
            calculate_and_update_min_diff(piece1, piece2, piece3, min_abs_diff_found); // DEBUG: Marked for key logic
        }
    }

    cout << min_abs_diff_found << endl;

    return 0;
}
